AND M.USE_YN = 'Y'

    AND M.MEMBER_ID LIKE CONCAT('%', #{memberId}, '%')


    AND (
        M.MEMBER_NAME LIKE CONCAT('%', #{memberName}, '%')
        OR M.NICKNAME LIKE CONCAT('%', #{memberName}, '%')
    )


    AND EXISTS (
        SELECT 1 FROM member_role MR
        WHERE MR.MEMBER_SEQ = M.MEMBER_SEQ AND MR.ROLE_CODE = #{roleCode}
    )


    AND M.GRADE_CODE = #{gradeCode}


    AND M.STATUS_CODE = #{statusCode}

