SELECT

FROM member M
WHERE M.OAUTH_PROVIDER = #{oauthProvider}
  AND M.OAUTH_SUBJECT = #{oauthSubject}
  AND M.USE_YN = 'Y'
LIMIT 1

SELECT

FROM member M
WHERE M.MEMBER_ID = #{memberId}
  AND M.USE_YN = 'Y'

    AND M.MEMBER_SEQ != #{memberSeq}

LIMIT 1

