UPDATE member SET MEMBER_NAME = #{memberName}, NICKNAME = #{nickname}, BIRTH_YMD = #{birthYmd}, EMAIL = #{email}, PROFILE_IMAGE_URL = #{profileImageUrl}, PROFILE_IMAGE_FILE_SEQ = #{profileImageFileSeq}, GENDER = #{gender}, PHONE = #{phone}, GRADE_CODE = #{gradeCode}, STATUS_CODE = #{statusCode}, MODIFY_DT = NOW(), MODIFY_ID = #{modifyId}, MODIFY_IP = #{modifyIp}
, MEMBER_PWD = #{memberPwd}
WHERE MEMBER_SEQ = #{memberSeq} AND USE_YN = 'Y'

UPDATE member
EMAIL = #{email}, MEMBER_NAME = #{memberName}, NICKNAME = #{nickname}, PROFILE_IMAGE_URL = #{profileImageUrl}, OAUTH_SYNC_DT = NOW(), MODIFY_DT = NOW(), MODIFY_ID = #{modifyId}, MODIFY_IP = #{modifyIp}
WHERE MEMBER_SEQ = #{memberSeq} AND USE_YN = 'Y'

UPDATE member
SET LAST_LOGIN_DT = NOW(),
    LAST_LOGIN_IP = #{loginIp}
WHERE MEMBER_SEQ = #{memberSeq}
  AND USE_YN = 'Y'
